<template>
    <modal-train  
        :show="show" 
        headerbackColor="#3b678b"  
        titlecolor="white" 
        :title="$t('add_ticket')" 
        @close="closeModal" 
        width="40%"
    >
        <template v-slot:body>
            <div class="ticket_modal_content p-3">
                <div class="form-group mb-1">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('ticket_number')}} <span class="text-danger">*</span></label>
                    <mdb-input 
                        class="m-0" 
                        v-model="ticket_data.ticket_number" 
                        :placeholder="$t('ticket_number')" 
                        size="md"
                        outline 
                        group 
                        type="text" 
                        validate 
                        error="wrong" 
                        success="right"
                    />
                </div>
                <div class="form-group mb-1">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('massa')}} <span class="text-danger">*</span></label>
                    <input 
                        class="ticket_number_input" 
                        v-model="ticket_data.massa_display" 
                        @input="formatMassa"
                        @focus="clearZero('massa')"
                        :placeholder="$t('massa')"
                        type="text"
                    />
                </div>
                <div class="form-group mb-1">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('price')}}</label>
                    <input 
                        class="ticket_number_input" 
                        v-model="ticket_data.price_display" 
                        @input="formatPrice"
                        @focus="clearZero('price')"
                        :placeholder="$t('price')"
                        type="text"
                    />
                </div>
                <div class="form-group mb-1">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('total_price')}}</label>
                    <input 
                        class="ticket_number_input" 
                        v-model="ticket_data.total_price_display" 
                        @input="formatTotalPrice"
                        @focus="clearZero('total_price')"
                        :placeholder="$t('total_price')"
                        type="text"
                    />
                </div>
                <div class="form-group mb-1">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('organization_name')}}</label>
                    <mdb-input 
                        class="m-0" 
                        v-model="ticket_data.organization_name" 
                        :placeholder="$t('organization_name')" 
                        size="md"
                        outline 
                        group 
                        type="text" 
                        validate 
                        error="wrong" 
                        success="right"
                    />
                </div>
                <div class="form-group">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('tegirmon_hisob')}}</label>
                    <erpSelectHisoblar
                        :options="hisob_list"
                        @select="selectHisob"
                        :selected="ticket_data.hisob_name"
                        :label="$t('tegirmon_hisob')"
                        size="sm"
                        class="bg-white mb-0"
                        url="/TegirmonHisoblar/getPagination?page=0&size=100"
                    />
                </div>
                <div class="form-group">
                    <label style="font-size: 13px; margin-bottom: 0px;">{{$t('note')}}</label>
                    <mdb-input 
                        class="m-0" 
                        v-model="ticket_data.note" 
                        :placeholder="$t('note')" 
                        size="md"
                        outline 
                        group 
                        type="textarea" 
                        validate 
                        error="wrong" 
                        success="right"
                    />
                </div>
                <div class="text-right mt-3">
                    <mdb-btn 
                        class="m-0 py-2 px-4 mr-2" 
                        @click="closeModal"
                        style="font-size: 12px;" 
                        color="secondary"
                        size="sm"
                    >
                        {{$t('cancel')}}
                    </mdb-btn>
                    <mdb-btn 
                        class="m-0 py-2 px-4" 
                        @click="saveTicket"
                        style="font-size: 12px;" 
                        color="success"
                        size="sm"
                        :disabled="saving"
                    >
                        <mdb-icon fas class="mr-1" icon="check"></mdb-icon> 
                        {{saving ? $t('saving') || 'Сохранение...' : $t('save')}}
                    </mdb-btn>
                </div>
            </div>
        </template>
    </modal-train>
</template>

<script>
import {mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
import erpSelectHisoblar from "./erpSelect.vue";

export default {
    name: 'AddTicketModal',
    components: {
        mdbInput, mdbBtn, mdbIcon,
        erpSelectHisoblar,
    },
    props: {
        show: {
            type: Boolean,
            default: false
        }
    },
    data() {
        return {
            saving: false,
            ticket_data: {
                ticket_number: '',
                massa: 0,
                massa_display: '0',
                price: 0,
                price_display: '0',
                total_price: 0,
                total_price_display: '0',
                organization_name: '',
                tegirmonHisoblar_id: null,
                hisob_name: '',
                note: ''
            },
            hisob_list: [],
        }
    },
    async mounted() {
        await this.fetchHisobList();
    },
    watch: {
        show(newVal) {
            if (!newVal) {
                // Modal yopilganda formani tozalash
                this.resetForm();
            }
        }
    },
    methods: {
        closeModal() {
            this.$emit('close');
        },
        async fetchHisobList(){
            try{
                const response = await fetch(this.$store.state.hostname + "/TegirmonHisoblar/getPagination?page=0&size=100");
                const data = await response.json();
                if(response.status == 201 || response.status == 200)
                {
                    this.hisob_list = data.items_list || [];
                }
            }
            catch{
                this.hisob_list = [];
            }
        },
        selectHisob(option){
            this.ticket_data.tegirmonHisoblar_id = option.id;
            this.ticket_data.hisob_name = option.name;
        },
        formatNumber(value) {
            if (!value && value !== 0) return '0';
            // String ga o'tkazish
            let strValue = String(value);
            // Faqat raqamlarni qoldirish
            let numbers = strValue.replace(/\D/g, '');
            if (numbers === '') return '0';
            // Formatlash: 789000 -> 789 000
            return numbers.replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
        },
        parseNumber(value) {
            if (!value) return 0;
            // String ga o'tkazish
            let strValue = String(value);
            // Formatdan tozalash: "789 000" -> 789000
            return parseFloat(strValue.replace(/\s/g, '')) || 0;
        },
        clearZero(field) {
            if (field === 'massa' && this.ticket_data.massa_display === '0') {
                this.ticket_data.massa_display = '';
            } else if (field === 'price' && this.ticket_data.price_display === '0') {
                this.ticket_data.price_display = '';
            } else if (field === 'total_price' && this.ticket_data.total_price_display === '0') {
                this.ticket_data.total_price_display = '';
            }
        },
        formatMassa(event) {
            let value = event.target.value;
            // Faqat raqam va nuqta qoldirish
            value = value.replace(/[^\d.]/g, '');
            // Bir nechta nuqta bo'lmasligi uchun
            let parts = value.split('.');
            if (parts.length > 2) {
                value = parts[0] + '.' + parts.slice(1).join('');
            }
            // Formatlash
            if (value === '' || value === '.') {
                this.ticket_data.massa_display = '';
                this.ticket_data.massa = 0;
            } else {
                let numValue = parseFloat(value) || 0;
                this.ticket_data.massa = numValue;
                // Butun qismni formatlash
                let intPart = Math.floor(numValue).toString();
                let formatted = this.formatNumber(intPart);
                if (parts.length > 1 && parts[1] && parts[1].length > 0) {
                    formatted += '.' + parts[1];
                }
                this.ticket_data.massa_display = formatted;
            }
            
            // Agar price yoki total_price mavjud bo'lsa, qayta hisoblash
            if (this.ticket_data.price > 0 && this.ticket_data.massa > 0) {
                this.ticket_data.total_price = this.ticket_data.price * this.ticket_data.massa;
                this.ticket_data.total_price_display = this.formatNumber(Math.floor(this.ticket_data.total_price).toString());
            } else if (this.ticket_data.total_price > 0 && this.ticket_data.massa > 0) {
                this.ticket_data.price = this.ticket_data.total_price / this.ticket_data.massa;
                this.ticket_data.price_display = this.formatNumber(Math.floor(this.ticket_data.price).toString());
            }
        },
        formatPrice(event) {
            let value = event.target.value;
            // Formatlash
            value = this.formatNumber(value);
            this.ticket_data.price_display = value;
            this.ticket_data.price = this.parseNumber(value);
            
            // total_price ni hisoblash: total_price = price * massa
            if (this.ticket_data.massa > 0 && this.ticket_data.price > 0) {
                this.ticket_data.total_price = this.ticket_data.price * this.ticket_data.massa;
                this.ticket_data.total_price_display = this.formatNumber(Math.floor(this.ticket_data.total_price).toString());
            }
        },
        formatTotalPrice(event) {
            let value = event.target.value;
            // Formatlash
            value = this.formatNumber(value);
            this.ticket_data.total_price_display = value;
            this.ticket_data.total_price = this.parseNumber(value);
            
            // price ni hisoblash: price = total_price / massa
            if (this.ticket_data.massa > 0 && this.ticket_data.total_price > 0) {
                this.ticket_data.price = this.ticket_data.total_price / this.ticket_data.massa;
                this.ticket_data.price_display = this.formatNumber(Math.floor(this.ticket_data.price).toString());
            }
        },
        resetForm() {
            this.ticket_data = {
                ticket_number: '',
                massa: 0,
                massa_display: '0',
                price: 0,
                price_display: '0',
                total_price: 0,
                total_price_display: '0',
                organization_name: '',
                tegirmonHisoblar_id: null,
                hisob_name: '',
                note: ''
            };
        },
        async saveTicket(){
            if(!this.ticket_data.ticket_number || !this.ticket_data.massa || this.ticket_data.massa === 0){
                if(this.$refs.message) {
                    this.$refs.message.error('please_fill');
                } else {
                    alert(this.$i18n.t('please_fill') || 'Пожалуйста, заполните обязательные поля');
                }
                return;
            }
            this.saving = true;
            // Formatdan tozalangan qiymatlarni olish
            let cleanMassa = this.ticket_data.massa;
            let cleanPrice = this.ticket_data.price || 0;
            let cleanTotalPrice = this.ticket_data.total_price || 0;
            
            const requestOptions = {
                method : "POST",
                headers: { "Content-Type" : "application/json" },
                body: JSON.stringify({
                    "ticket_number" : this.ticket_data.ticket_number,
                    "massa" : cleanMassa,
                    "price": cleanPrice,
                    "total_price": cleanTotalPrice,
                    "organization_name": this.ticket_data.organization_name || '',
                    "tegirmonHisoblar_id": this.ticket_data.tegirmonHisoblar_id,
                    "hisob_name": this.ticket_data.hisob_name || '',
                    "note": this.ticket_data.note || '',
                    "tegirmonAuthId": localStorage.AuthId ? parseInt(localStorage.AuthId) : null,
                    "id" : 0,
                    "active_status": true
                })
            };
            try{
                const response = await fetch(this.$store.state.hostname + "/TegirmonTicket", requestOptions);
                this.saving = false;
                if(response.status == 201 || response.status == 200)
                {
                    const tryjson = await response.json();
                    console.log(tryjson)
                    this.closeModal();
                    this.resetForm();
                    this.$emit('saved');
                    if(this.$refs.message) {
                        this.$refs.message.success('Added_successfully');
                    }
                }
                else{
                    const data = await response.text();
                    if(this.$refs.message) {
                        this.$refs.message.error('Failed_to_add');
                    } else {
                        alert(data || this.$i18n.t('Failed_to_add') || 'Ошибка при добавлении');
                    }
                }
            }
            catch(error){
                this.saving = false;
                console.error('Error saving ticket:', error);
                if(this.$refs.message) {
                    this.$refs.message.error('network_ne_connect');
                } else {
                    alert(this.$i18n.t('network_ne_connect') || 'Ошибка сети');
                }
            }
        }
    },
}
</script>

<style lang="scss" scoped>
.ticket_number_input {
  width: 100%;
  padding: 8px 12px;
  font-size: 14px;
  border: 1px solid #ced4da;
  border-radius: 4px;
  outline: none;
  transition: all 0.3s ease;
  background: white;
  color: #495057;
}

.ticket_number_input:focus {
  border-color: #4285F4;
  box-shadow: 0 0 0 0.2rem rgba(66, 133, 244, 0.25);
}

.ticket_number_input::placeholder {
  color: #6c757d;
  opacity: 0.6;
}
</style>

